,CAAzB,EAAnBF,CAAAA,GAAAA,SAAAA,CAAKtD;UACxB2D,eAA+BC,MAAhBP,gBAAgBO,WAAAA,EAAAA,EAAAA,EAAhBN,aAA4BC,CAAD,EAAIM,CAA/BP;;YAA4B;YAAG;YAAGG,OAAAF,CAACO,KAAAA,CAAAA,EAAnCR,CAAgBM;UAE/B5E,IAAA+E,2BAAAA,CAA0BJ,YAA1BI;UACA/E,IAAAgF,2BAAAA,CAA0BL,YAA1BK;UACAhF,IAAAiF,oCAAAA,CAAmCN,YAAnCM;UAEAzB,aACSxC,MADA2D,YACA3D,OAAAA,EAAAA,EAAAA,EADAsD,aACQV,KAAD,EAAQpD,OADf8D;;YACQ;YAAO;YAASG,OAAAS,UAAItF,KAAAA,CAAKgE,KAAT,EAAgBpD,OAAON,QAAAA,CAAAA,CAAnBN,CAA2BM,QAAAA,CAAAA,EADvDoE,CACAtD,CACAd,QAAAA,CAAAA;UAETkD,OAAApD;QAZFoD,CAAAA;;AAmBAsB,QAAAA,mCAAAA,+BAAwBlD,CAAxBkD;AAAAA,UAAAA;;;UAEE,IAAA,QAAKjD,aAAL,EADAC,CAAAA,YAAKF,CAALE,CACA,CAAA;YACE,OAAOG,WAAKjC,KAAAA,CAAK4B,CAAV,EAAaA,CAAR5B;UADd,OAEA,IAAA,QAAKiC,WAAL,EAxNR,SAwNQ,CAAA;YACE,IAAG,CAAA,QAAAL,CAAC2D,OAAAA,CAAAA,CAAMC,UAAAA,CAAO3D,aAAP2D,CAAP,CAAA,IAAA,CAAA,QAA0B5D,CAAC6D,KAAAA,CAAAA,CAAID,UAAAA,CAAO3D,aAAP2D,CAA/B,CAAA,CAAA,CAAH;cACE,OAAO5D;YADT;UADF;YAHA;UAGA;UAMAkD,OAAA1E,IAAAmC,OAAAA,CACEC,eADF,EAEE,EAAA,GAAA,CAAGC,SAAH,CAAA,GAASqC,IAAT,GAAA,CAAalD,CAAb,CAAA,GAAekD,IAAf,GAAA,CAAmBlD,CAACc,OAAAA,CAAAA,CAApB,CAAA,GAA2BoC,gDAF7BvC;QAVFuC,CAAAA;;AAqBAK,QAAAA,yCAAAA,qCAA8BJ,YAA9BI;AAAAA,UAAAA;;;UACEO,UAAUrC;UACVW,QAAQe,YAAYY,OAAAA,CAAAA,CAAMtE,OAAAA,CAACK,CAADL;UAC1B,KAAA,QAAO2C,KAAKhC,aAAAA,CAAU0D,OAAV1D,CAAZ,CAAA;YACE5B,IAAAmC,OAAAA,CACE0B,gBADF,EAEE,EAAA,GAAA,CAAGxB,SAAH,CAAA,GAAS0C,eAAT,GAAA,CAAwBO,OAAxB,CAAA,GAAgCP,oBAAhC,GAAA,CAAoDnB,KAApD,CAFFzB;UADF;UAOA4C,OAAA/E;QAVF+E,CAAAA;;AAkBAC,QAAAA,yCAAAA,qCAA8BL,YAA9BK;AAAAA,UAAAA;;;UACEQ,UAAuBC,UAAbxC,gBAAawC,EAAEtC,iBAAFsC;UACvB7B,QAAQe,YAAYe,MAAAA,CAAAA,CAAKzE,OAAAA,CAACK,CAADL;UACzB,KAAA,QAAO2C,KAAKhC,aAAAA,CAAU4D,OAAV5D,CAAZ,CAAA;YACE5B,IAAAmC,OAAAA,CACE0B,gBADF,EAEE,EAAA,GAAA,CAAGxB,SAAH,CAAA,GAAS2C,eAAT,GAAA,CAAwBQ,OAAxB,CAAA,GAAgCR,oBAAhC,GAAA,CAAoDpB,KAApD,CAFFzB;UADF;UAOA6C,OAAAhF;QAVFgF,CAAAA;QAkBArF,OAAAsF,kDAAAA,8CAAuCN,YAAvCM;AAAAA,UAAAA;;;UACcU,MAAZhB,YAAYgB,aAAAA,EAAAA,CAAW5D,CAAX4D,CAAAA,EAAZC,aAA8BC,EAAD,EAAKC,EAAlCF,EAAAG;AAAAA;;;YAA8B;YAAI;YAChCC,KAAKH,EAAE5E,OAAAA,CAACK,CAADL;YACPgF,KAAKH,EAAE7E,OAAAA,CAACK,CAADL;YAEPiF,OAAOF,EAAEG,KAAAA,CAAAA;YACTC,eAAoBC,SAALH,IAAKG,EAAE9E,CAAF8E;YAEpB,IAAA,QAAGJ,EAAErE,aAAAA,CAAUsE,IAAVtE,CAAL,CAAA;cACE5B,IAAAmC,OAAAA,CAAM0B,gBAAN,EAAkB,EAAA,GAAA,CAAGxB,SAAH,CAAA,GAAS0D,mBAAT,GAAA,CAA4BC,EAA5B,CAAA,GAA+BD,OAA/B,GAAA,CAAsCE,EAAtC,CAAlB9D;YADF;YAIA,IAAA,QAAO8D,EAAErE,aAAAA,CAAUwE,YAAVxE,CAAT,CAAA;cAzRVmE,OAAA;YAyRU;cACEA,OAAA/F,IAAAmC,OAAAA,CAAM0B,gBAAN,EAAkB,EAAA,GAAA,CAAGxB,SAAH,CAAA,GAAS0D,eAAT,GAAA,CAAwBC,EAAxB,CAAA,GAA2BD,OAA3B,GAAA,CAAkCE,EAAlC,CAAlB9D;YADF,EAXFyD,CAAAA,GAAAA,SAAAA,CAAYD;UAgBZV,OAAAjF;QAjBFiF,CAAAA;MA5OFtF,GAAAA,WAAAA,EAAAA,IAAAA;IA9BFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>207, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/BlackJacket_Korean.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'bcdice/dice_table/range_table'\n\nmodule BCDice\n  module GameSystem\n    class BlackJacket_Korean < BlackJacket\n      # ゲームシステムの識別子\n      ID = 'BlackJacket:Korean'\n\n      # ゲームシステム名\n      NAME = '블랙재킷RPG'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = '国際化:Korean:블랙재킷RPG'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~INFO_MESSAGE_TEXT\n        ・행위 판정（BJx）\n        　x：성공률\n        　예）BJ80\n        　크리티컬,펌블 여부는 자동으로 판정합니다.\n        　「BJ50+20-30」처럼 값을 가감하여 기재할 수 있습니다.\n        　성공률의 상한은 100％、하한은 ０％ 입니다.\n        ・데스 차트 (DCxY)\n        　x：차트 종류. 육체：DCL, 정신：DCS, 환경：DCC\n        　Y=마이너스 값\n        　예）DCL5：라이프 마이너스 값 5 + 1D10 판정\n        　　　DCS3：새니티 마이너스 값 3 + 1D10 판정\n        　　　DCC0：크레딧 마이너스 값 0 + 1D10 판정\n        ・챌린지・패널티 차트（CPC）\n        ・사이드 트랙 차트（STC）\n      INFO_MESSAGE_TEXT\n\n      def eval_game_system_specific_command(command)\n        resolute_action(command) || roll_death_chart(command) || roll_tables(command, TABLES)\n      end\n\n      private\n\n      def resolute_action(command)\n        m = /^BJ(\\d+([+-]\\d+)*)$/.match(command)\n        unless m\n          return nil\n        end\n\n        success_rate = ArithmeticEvaluator.eval(m[1])\n\n        roll_result, dice10, dice01 = roll_d100\n        roll_result_text = format('%02d', roll_result)\n\n        result = action_result(roll_result, dice10, dice01, success_rate)\n\n        sequence = [\n          \"행위판정(성공률:\#{success_rate}％)\",\n          \"1D100[\#{dice10},\#{dice01}]=\#{roll_result_text}\",\n          roll_result_text.to_s,\n          result.text\n        ]\n\n        result.text = sequence.join(\" ＞ \")\n        result\n      end\n\n      SUCCESS_STR = \"성공\"\n      FAILURE_STR = \"실패\"\n      CRITICAL_STR = (SUCCESS_STR + \" ＞ 크리티컬! 파워의 대가(코스트) 절반으로 감소\").freeze\n      FUMBLE_STR = (FAILURE_STR + \" ＞ 펌블! 파워의 대가(코스트) 2배 & 재굴림 불가\").freeze\n      MISERY_STR = (FAILURE_STR + \" ＞ 미저리! 파워의 대가(코스트) 2배 & 재굴림 불가\").freeze\n\n      def action_result(total, tens, ones, success_rate)\n        if total == 100\n          Result.fumble(MISERY_STR)\n        elsif success_rate <= 0\n          Result.fumble(FUMBLE_STR)\n        elsif total <= success_rate - 100\n          Result.critical(CRITICAL_STR)\n        elsif tens == ones\n          if total <= success_rate\n            Result.critical(CRITICAL_STR)\n          else\n            Result.fumble(FUMBLE_STR)\n          end\n        elsif total <= success_rate\n          Result.success(SUCCESS_STR)\n        else\n          Result.failure(FAILURE_STR)\n        end\n      end\n\n      def roll_d100\n        dice10 = @randomizer.roll_once(10)\n        dice10 = 0 if dice10 == 10\n        dice01 = @randomizer.roll_once(10)\n        dice01 = 0 if dice01 == 10\n\n        roll_result = dice10 * 10 + dice01\n        roll_result = 100 if roll_result == 0\n\n        return roll_result, dice10, dice01\n      end\n\n      class DeathChart\n        def initialize(name, chart)\n          @name = name\n          @chart = chart.freeze\n\n          if @chart.size != 11\n            raise ArgumentError, \"unexpected chart size \#{name.inspect} (given \#{@chart.size}, expected 11)\"\n          end\n        end\n\n        # @param randomizer [Randomizer]\n        # @param minus_score [Integer]\n        # @return [String]\n        def roll(randomizer, minus_score)\n          dice = randomizer.roll_once(10)\n          key_number = dice + minus_score\n\n          key_text, chosen = at(key_number)\n\n          return \"데스 차트（\#{@name}）[마이너스 값:\#{minus_score} + 1D10(->\#{dice}) = \#{key_number}] ＞ \#{key_text} ： \#{chosen}\"\n        end\n\n        private\n\n        # key_numberの10から20がindexの0から10に対応する\n        def at(key_number)\n          if key_number < 10\n            [\"10이하\", @chart.first]\n          elsif key_number > 20\n            [\"20이상\", @chart.last]\n          else\n            [key_number.to_s, @chart[key_number - 10]]\n          end\n        end\n      end\n\n      def roll_death_chart(command)\n        m = /^DC([LSC])(\\d+)$/i.match(command)\n        unless m\n          return m\n        end\n\n        chart = DEATH_CHARTS[m[1]]\n        minus_score = m[2].to_i\n\n        return chart.roll(@randomizer, minus_score)\n      end\n\n      DEATH_CHARTS = {\n        'L' => DeathChart.new(\n          '육체',\n          [\n            \"효과 없음. 당신은 기적적으로 목숨을 건졌다. 싸움은 계속된다.\",\n            \"격한 통증을 느낀다. 이후 이벤트가 끝날 때까지 모든 판정의 성공률에 -10%.\",\n            \"더이상 몸이 움직이지 않는다…… 당신은 [경직 2]를 받는다.\",\n            \"혼신의 일격!! 당신은 〈생존〉 판정을 한다. 실패할 경우 [사망]한다.\",\n            \"갑자기 눈앞이 캄캄해진다. 당신은 [기절 2]를 받는다.\",\n            \"이후, 이벤트 종료까지 모든 판정의 성공률 -20%.\",\n            \"기록적인 일격!! 당신은 〈생존〉 -20% 으로 판정한다. 실패할 경우 [사망]한다.\",\n            \"사느냐 죽느냐. 당신은 [빈사 2]를 받는다.\",\n            \"역사에 한 획을 그을 일격!! 당신은 <생존> -30% 으로 판정한다. 실패할 경우 [사망]한다.\",\n            \"이후, 이벤트 종료 시까지 모든 판정의 성공률 -30%.\",\n            \"신화적 일격!! 공중에서 세 바퀴 정도 회전한 후 땅바닥에 내동댕이쳐진다. 보기에도 끔찍한 모습. 육체는 원형을 유지하지 못했다. 당신은 [사망]한다.\",\n          ]\n        ),\n        'S' => DeathChart.new(\n          '정신',\n          [\n            \"효과 없음. 당신은 이를 악물고 스트레스를 견뎌냈다.\",\n            \"이후, 이벤트 종료 시까지 모든 판정의 성공률 -10%.\",\n            \"말할 수 없는 공포가 당신을 엄습한다. 당신은 [공포 2]를 받는다.\",\n            \"상처를 많이 받았다. 당신은 〈의지〉 판정을 한다. 실패할 경우 [절망] 상태가 되어서 NPC가 된다.\",\n            \"의식을 잃었다. 당신은 [기절 2]를 받는다.\",\n            \"이후, 이벤트 종료 시까지 모든 판정의 성공률 -20%.\",\n            \"신뢰했던 자에게 속은 아픔. 당신은 〈의지〉 -20% 으로 판정한다. 실패할 경우, [절망] 상태가 되어서 NPC가 된다.\",\n            \"동료에게 배신 당한 것일지도 모른다. 당신은 [혼란 2]를 받는다.\",\n            \"너무나 참혹한 현실. 당신은 〈의지〉 -30% 으로 판정한다. 실패할 경우 [절망] 상태가 되어서 NPC가 된다.\",\n            \"이후, 이벤트 종료 시까지 모든 판정의 성공률 -30%.\",\n            \"천지개벽의 이치 그 이상. 그것은 인류의 인식한계를 뛰어넘는 무언가였다. 당신은 [절망] 상태가 된 후 NPC가 된다.\",\n          ]\n        ),\n        'C' => DeathChart.new(\n          '환경',\n          [\n            \"효과 없음. 당신은 뒤숭숭한 소문을 무시했다.\",\n            \"이후, 이벤트 종료 시까지 모든 판정의 성공률 -10%.\",\n            \"위험한 상태! 이후, 라운드 종료 시까지 당신은 카르마를 사용할 수 없다.\",\n            \"나쁜 소문이 돈다. 당신은 〈교섭〉 판정을 한다. 실패할 경우 당신은 동료들의 신뢰를 잃고 [무연고] 상태가 된 후 NPC가 된다.\",\n            \"이후, 시나리오 종료 시까지 대가(코스트)에 크레딧을 소비하는 파워를 사용할 수 없다.\",\n            \"당신의 악평이 세상에 널리 알려진다. 협력자로부터의 지원이 중단된다. 이후 시나리오 종료 시까지 모든 판정의 성공률 -20%.\",\n            \"배신!! 당신은 〈경제〉 -20% 으로 판정한다. 실패할 경우 당신은 주위로부터 신용을 잃고, [무연고] 상태가 되어 NPC가 된다.\",\n            \"이후, 시나리오 종료 시까지 【환경】 계열의 기능 레벨이 모두 0이 된다.\",\n            \"날조 보도? 기억나지 않는 배신 행위가 특종으로 보도된다. 당신은 〈심리〉 -30% 으로 판정한다. 실패할 경우 당신은 인간으로서의 존엄성을 잃고, [무연고]가 된다.\",\n            \"이후, 이벤트 종료 시까지 모든 판정 성공률 -30%.\",\n            \"당신의 이름은 사상 최악의 오점으로 영원히 역사에 새겨진다. 이제 당신을 믿는 동료는 없고 당신을 돕는 사회도 없다. 당신은 [무연고] 상태가 된 후 NPC가 된다.\",\n          ]\n        )\n      }.freeze\n\n      TABLES = {\n        \"CPC\" => DiceTable::Table.new(\n          \"챌린지・패널티 차트\",\n          \"1D10\",\n          [\n            \"사망\\n도와야 할 NPC (히로인 등)가 사망한다.\",\n            \"검은 별\\n적이 목적을 성취하고, 사건은 PC의 패배로 끝난다. 그대로 여운 페이즈로 넘어갈 것.\",\n            \"활성\\n적 보스의 라이프를 2배로 한 다음 결전 페이즈를 개시한다.\",\n            \"공세\\n적 보스의 대미지에 +2D6의 수정을 준 후 결전 페이즈를 개시한다.\",\n            \"대거\\n적의 수(보스 제외)를 2배로 한 후 결전 페이즈를 개시한다.\",\n            \"암흑\\n모든 에리어(구역)을 [어둠]으로 만든 다음 결전 페이즈를 개시한다.\",\n            \"맹화\\n전투 에리어(구역) 2개를 [대미지 존 2]로 취급한 후, 결전 페이즈를 개시한다.\",\n            \"복병\\n적의 절반을 에리어(구역) 1과 에리어(구역) 2로 이동시킨 후, 결전 페이즈를 개시한다.\",\n            \"만복\\n보스 이외의 적의 라이프를 모두 2배로 한 다음, 결전 페이즈를 개시한다.\",\n            \"봉인\\nPC는 결전 페이즈 동안 카르마를 사용할 수 없다. 결전 페이즈를 개시한다.\"\n          ]\n        ),\n        \"STC\" => DiceTable::Table.new(\n          \"사이드 트랙 차트\",\n          \"1D10\",\n          [\n            \"해후\\n우연히 NPC와 만난다. 어떤 NPC가 나타날지는 GM이 결정한다.\",\n            \"사고\\교통사고를 당한다. 주변에서 패닉이 일어나고 있을지도 모른다.\",\n            \"낮잠\\n지독한 졸음이 몰려온다. 설마, 신참 빌런의 능력인가?\",\n            \"고백\\nNPC 한 명이 지금까지 간직하고 있던 마음을 당신에게 고백한다.\",\n            \"설정\\n새로운 설정이 밝혀진다. 사실은 NPC의 아버지였다든가, 선천적으로 눈이 보이지 않는다든가.\",\n            \"자객\\n누군가로부터 공격을 받는다. 제3세력인가?\",\n            \"불청객\\n우연히 원수 한 명과 마주친다. 상황에 따라서 바로 전투가 발생할지도 모른다.\",\n            \"의심\\n수상한 사람을 눈치챘다. 따라가야 하나? 무시해야 하나?\",\n            \"조우\\n시나리오와 관계없는 빌런 조직과 조우한다.\",\n            \"평화\\n별일 없었다.\",\n          ]\n        ),\n      }.freeze\n\n      register_prefix(\n        'BJ',\n        'DC[LSC]',\n        TABLES.keys\n      )\n    end\n  end\nend\n"], :names=>["<main>", "self", "require", "<module:BCDice>", "<module:GameSystem>", "<class:BlackJacket_Korean>", "eval_game_system_specific_command", "command", "$ret_or_1", "$ret_or_2", "resolute_action", "roll_death_chart", "roll_tables", "TABLES", "private", "m", "match", "success_rate", "ArithmeticEvaluator", "eval", "[]", "1", "roll_d100", "roll_result", "dice10", "dice01", "roll_result_text", "format", "result", "action_result", "sequence", "to_s", "text", "text=", "join", "+", "SUCCESS_STR", "freeze", "FAILURE_STR", "total", "tens", "ones", "100", "Result", "fumble", "MISERY_STR", "<=", "0", "FUMBLE_STR", "-", "critical", "CRITICAL_STR", "success", "failure", "@randomizer", "roll_once", "10", "*", "<class:DeathChart>", "initialize", "name", "chart", "@name", "@chart", "size", "11", "raise", "ArgumentError", "inspect", "rol